insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:g-4-talking-about-the-past:match:cf4fe9cf', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “estuve”?", "options": ["I was (place/state)", "he/she ate", "I spoke", "I was (description)"]}'::jsonb, '{"answer": 0, "explain": "“estuve” means: I was (place/state)"}'::jsonb),
('spanish:g-4-talking-about-the-past:match:69e2fd05', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “hablaba”?", "options": ["I had", "I used to speak", "I went / I was", "I was (description)"]}'::jsonb, '{"answer": 1, "explain": "“hablaba” means: I used to speak"}'::jsonb),
('spanish:g-4-talking-about-the-past:match:9db196cf', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “comía”?", "options": ["I used to eat / was eating", "I had", "I have eaten", "I was (description)"]}'::jsonb, '{"answer": 0, "explain": "“comía” means: I used to eat / was eating"}'::jsonb),
('spanish:g-4-talking-about-the-past:match:e1f39e9a', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “era”?", "options": ["I did / made", "I used to speak", "I was (description)", "I spoke"]}'::jsonb, '{"answer": 2, "explain": "“era” means: I was (description)"}'::jsonb),
('spanish:g-4-talking-about-the-past:match:0d9d18f8', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “iba”?", "options": ["we lived", "I did / made", "I used to go", "I was (place/state)"]}'::jsonb, '{"answer": 2, "explain": "“iba” means: I used to go"}'::jsonb),
('spanish:g-4-talking-about-the-past:match:1ba531fb', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “he comido”?", "options": ["he/she ate", "I used to speak", "I used to go", "I have eaten"]}'::jsonb, '{"answer": 3, "explain": "“he comido” means: I have eaten"}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:e7cd47c5', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Voy a estudiar esta noche.\" data-listen></span><br>Listen. What is the plan?", "options": ["To study tonight", "To study tomorrow morning instead", "To not study at all tonight", "I already studied last night"]}'::jsonb, '{"answer": 0, "explain": "‘voy a estudiar esta noche’ = I’m going to study tonight. The traps change the time, add a negative, or switch to the past."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:913f8b18', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Tendré que trabajar el sábado.\" data-listen></span><br>Listen. What is being said?", "options": ["I will have to work on Saturday", "I would have to work on Saturday", "I had to work last Saturday", "I don’t have to work on Saturday"]}'::jsonb, '{"answer": 0, "explain": "‘tendré que’ = I will have to (future). Trap B swaps it for the conditional (tendría), C for the past, D adds a negative."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:568306ca', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "Which is the correct future form of ‘vivir’ for ‘nosotros’?", "options": ["viviremos", "viviréis", "viviríamos", "vivimos"]}'::jsonb, '{"answer": 0, "explain": "The nosotros future ending is -emos → viviremos. viviréis is vosotros, viviríamos is conditional, vivimos is present."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:ae7797d2', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Si gano la lotería, ___ una casa nueva.’ (I would buy)", "options": ["compraría", "compraré", "compro", "comprarían"]}'::jsonb, '{"answer": 0, "explain": "compraría = I would buy (conditional). compraré is future, compro is present, comprarían is conditional but for ‘ellos’."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:9a2dabc5', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "What does ‘me gustaría viajar a Japón’ mean?", "options": ["I would like to travel to Japan", "I am going to travel to Japan", "I travelled to Japan last year", "I like travelling, and Japan is nice"]}'::jsonb, '{"answer": 0, "explain": "me gustaría + infinitive = I would like to. B uses ir a, C is past tense, D breaks the phrase apart."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:cab778e0', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses the irregular future stem for ‘hacer’?", "options": ["Mañana haré la tarea.", "Mañana haceré la tarea.", "Mañana hacía la tarea siempre.", "Mañana haría la tarea seguramente."]}'::jsonb, '{"answer": 0, "explain": "hacer → har- + é = haré. ‘haceré’ keeps the full infinitive wrongly, ‘hacía’ is imperfect, ‘haría’ is conditional."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:052102f7', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Cuando tenga dieciocho años, aprenderé a conducir.\" data-listen></span><br>Listen. What will happen at 18?", "options": ["They will learn to drive", "They will buy a car", "They have already learned to drive", "They will not be allowed to drive"]}'::jsonb, '{"answer": 0, "explain": "‘aprenderé a conducir’ = I will learn to drive. The traps swap the action, the tense, or add a negative."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:9c1d8cef', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Ellos ___ venir a la fiesta el viernes.’ (they will be able to)", "options": ["podrán", "poderán", "pueden", "podrían"]}'::jsonb, '{"answer": 0, "explain": "poder → podr- + án = podrán. ‘poderán’ wrongly keeps the infinitive stem, ‘pueden’ is present, ‘podrían’ is conditional."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:a9bbca77', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses the present subjunctive?", "options": ["Es importante que hagas los deberes.", "Es importante que haces los deberes.", "Es importante hacer que los deberes.", "Es importante harás los deberes pronto."]}'::jsonb, '{"answer": 0, "explain": "‘es importante que’ + new subject needs the subjunctive: hagas. B keeps the ordinary present, C and D are ungrammatical word orders."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:mcq:137b2db0', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'mcq', 'mcq', 1, '{"question": "What is the difference between ‘tendré’ and ‘tendría’?", "options": ["tendré = will have, tendría = would have", "tendré = would have, tendría = will have", "they mean exactly the same thing", "tendré is present tense, tendría is past tense"]}'::jsonb, '{"answer": 0, "explain": "The -é ending marks the future (will), the -ía ending marks the conditional (would) — same stem, different meaning."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:21667d5d', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "The near future (ir a + infinitive) is formed with a conjugated form of ‘ir’, then ‘a’, then an infinitive."}'::jsonb, '{"answer": true, "explain": "voy a estudiar, vas a comer, va a salir — always ir + a + infinitive."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:9558d317', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "The simple future removes -ar/-er/-ir before adding the endings, like the imperfect tense."}'::jsonb, '{"answer": false, "explain": "Future endings attach to the WHOLE infinitive (hablar+é); it is the stem for irregular verbs that changes, not a rule about all verbs."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:aba947f2', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "‘tendré’, ‘haré’, ‘podré’ and ‘saldré’ all have irregular stems in the future."}'::jsonb, '{"answer": true, "explain": "tener→tendr-, hacer→har-, poder→podr-, salir→saldr- — all irregular future stems."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:d7f2d9bd', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "The conditional uses a completely different stem from the future for irregular verbs."}'::jsonb, '{"answer": false, "explain": "The conditional reuses the SAME stem as the future (e.g. tendr-); only the endings change."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:6711242f', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "‘me gustaría’ is followed by an infinitive, just like ‘me gusta’."}'::jsonb, '{"answer": true, "explain": "me gustaría estudiar / me gustaría viajar — same pattern as me gusta + infinitive."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:56cf9297', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "Every future and conditional ending carries a written accent, except the ‘nosotros’ future form."}'::jsonb, '{"answer": true, "explain": "hablaremos has no accent, but every other future/conditional ending does (é, ás, á, éis, án / ía, ías, ía, íamos, íais, ían)."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:5906b0a7', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "‘Es importante que estudies’ uses the present subjunctive because of ‘que’ plus a change of subject after a trigger phrase."}'::jsonb, '{"answer": true, "explain": "es importante que + new subject triggers the subjunctive: estudies."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tf:2f425367', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tf', 'tf', 1, '{"question": "The perfect tense is formed with the PRETERITE of haber plus a past participle."}'::jsonb, '{"answer": false, "explain": "The perfect uses the PRESENT of haber (he/has/ha/hemos/habéis/han) + past participle."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:8d2f389c', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about near-future plans? (ir a + infinitivo)", "reading": "<p>The easiest way to talk about the future is <strong>ir a + infinitivo</strong> — literally “to go to do something”. Conjugate <span data-say=\"ir\">ir</span> and add an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"voy a\">voy a</span></td><td>I am going to</td><td><span data-say=\"vamos a\">vamos a</span></td><td>we are going to</td></tr>\n              <tr><td><span data-say=\"vas a\">vas a</span></td><td>you are going to</td><td><span data-say=\"vais a\">vais a</span></td><td>you all are going to</td></tr>\n              <tr><td><span data-say=\"va a\">va a</span></td><td>he/she is going to</td><td><span data-say=\"van a\">van a</span></td><td>they are going to</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy a estudiar en la universidad.\">Voy a estudiar en la universidad.</span> — <em>I am going to study at university.</em> Never drop the little word <strong>a</strong> — <span data-say=\"voy estudiar\">voy estudiar</span> is missing it and is wrong.</p>", "question": "What is wrong with ‘Voy estudiar mañana’?", "options": ["It is missing ‘a’ between voy and the infinitive", "It should not use the verb ‘ir’ at all here", "The infinitive ‘estudiar’ should be conjugated instead", "‘mañana’ must come before ‘voy’, not after it"]}'::jsonb, '{"answer": 0, "explain": "ir a + infinitive always needs ‘a’ linking the conjugated ir and the infinitive: voy a estudiar."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:c62d1484', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "How do I form the simple future for regular verbs?", "reading": "<p>For regular verbs, add these endings to the <strong>whole infinitive</strong> — don’t remove -ar/-er/-ir first: <strong>-é, -ás, -á, -emos, -éis, -án</strong>. The same endings work for -ar, -er and -ir verbs.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaré\">hablaré</span></td><td>I will speak</td><td><span data-say=\"hablaremos\">hablaremos</span></td><td>we will speak</td></tr>\n              <tr><td><span data-say=\"comerás\">comerás</span></td><td>you will eat</td><td><span data-say=\"comeréis\">comeréis</span></td><td>you all will eat</td></tr>\n              <tr><td><span data-say=\"vivirá\">vivirá</span></td><td>he/she will live</td><td><span data-say=\"vivirán\">vivirán</span></td><td>they will live</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El año que viene, viviré en Madrid y estudiaré español.\">El año que viene, viviré en Madrid y estudiaré español.</span> — <em>Next year, I will live in Madrid and study Spanish.</em> Every future ending except <strong>-emos</strong> carries a written accent.</p>", "question": "Complete: ‘Mañana, tú ___ con el director.’ (you will speak)", "options": ["hablarás", "hablaras", "hablas", "hablarías"]}'::jsonb, '{"answer": 0, "explain": "hablarás is the future tú form — note the accented á. hablaras drops the accent, hablas is present tense, and hablarías is the CONDITIONAL, not future."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:777dcbd5', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "Which verbs have an irregular stem in the future?", "reading": "<p>A group of common verbs use a shortened or changed stem before the <strong>same endings</strong> (-é, -ás, -á, -emos, -éis, -án). Learn these:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tendré\">tendré</span></td><td>I will have (tener)</td><td><span data-say=\"haré\">haré</span></td><td>I will do/make (hacer)</td></tr>\n              <tr><td><span data-say=\"podré\">podré</span></td><td>I will be able to (poder)</td><td><span data-say=\"saldré\">saldré</span></td><td>I will leave (salir)</td></tr>\n              <tr><td><span data-say=\"vendré\">vendré</span></td><td>I will come (venir)</td><td><span data-say=\"diré\">diré</span></td><td>I will say (decir)</td></tr>\n              <tr><td><span data-say=\"querré\">querré</span></td><td>I will want (querer)</td><td><span data-say=\"pondré\">pondré</span></td><td>I will put (poner)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El sábado, tendré que estudiar pero después saldré con mis amigos.\">El sábado, tendré que estudiar pero después saldré con mis amigos.</span> — <em>On Saturday I will have to study but afterwards I will go out with my friends.</em> Never write “tenerá” — the stem changes to <strong>tendr-</strong> before any future ending.</p>", "question": "Complete: ‘El sábado, ella ___ que estudiar.’ (she will have to)", "options": ["tendrá", "tenerá", "tiene", "tendría"]}'::jsonb, '{"answer": 0, "explain": "tener has the irregular future stem tendr-. ‘tenerá’ wrongly keeps the full infinitive stem, ‘tiene’ is present tense, and ‘tendría’ is the conditional, not future."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:87703574', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "How do I form the conditional? (would…)", "reading": "<p>The conditional uses the <strong>same stem</strong> as the future (regular = whole infinitive; irregular = the same shortened stem), plus a different set of endings: <strong>-ía, -ías, -ía, -íamos, -íais, -ían</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaría\">hablaría</span></td><td>I would speak</td><td><span data-say=\"viviríamos\">viviríamos</span></td><td>we would live</td></tr>\n              <tr><td><span data-say=\"tendría\">tendría</span></td><td>I would have</td><td><span data-say=\"haría\">haría</span></td><td>I would do/make</td></tr>\n              <tr><td><span data-say=\"podría\">podría</span></td><td>I would be able to</td><td><span data-say=\"saldrías\">saldrías</span></td><td>you would leave</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Con más dinero, viajaría por el mundo y compraría una casa grande.\">Con más dinero, viajaría por el mundo y compraría una casa grande.</span> — <em>With more money, I would travel the world and buy a big house.</em> Every conditional ending carries a written accent.</p>", "question": "Complete: ‘Con más tiempo, (yo) ___ más deporte.’ (I would do)", "options": ["haría", "haré", "hago", "harían"]}'::jsonb, '{"answer": 0, "explain": "haría is the conditional (would). haré is future (will), hago is present, and harían is conditional but for ‘ellos’ (they), not ‘yo’."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:b5d1e015', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "How do I politely say what I would like? (me gustaría)", "reading": "<p><span data-say=\"me gustaría\">me gustaría</span> (I would like) is one of the most useful exam phrases. It is the conditional of <strong>gustar</strong>, so it behaves just like <em>me gusta</em> and is followed by an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me gustaría\">me gustaría</span></td><td>I would like</td><td><span data-say=\"te gustaría\">te gustaría</span></td><td>you would like</td></tr>\n              <tr><td><span data-say=\"le gustaría\">le gustaría</span></td><td>he/she would like</td><td><span data-say=\"nos gustaría\">nos gustaría</span></td><td>we would like</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Me gustaría estudiar en el extranjero después del instituto.\">Me gustaría estudiar en el extranjero después del instituto.</span> — <em>I would like to study abroad after school.</em> Like <em>me gusta</em>, it does not agree with what follows — it stays as ‘gustaría’, never ‘gustarían’, when followed by an infinitive.</p>", "question": "What must follow ‘me gustaría’ in a sentence like ‘me gustaría estudiar’?", "options": ["an infinitive, exactly like after me gusta", "a verb conjugated to agree with ‘yo’, like hago", "the word ‘que’ followed by a new subject", "a plural noun with no verb at all"]}'::jsonb, '{"answer": 0, "explain": "me gustaría + infinitive = I would like to do something, exactly like me gusta + infinitive (me gusta estudiar)."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:learn:28436641', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'learn', 'mcq', 1, '{"readingTitle": "Higher: the perfect, pluperfect and an intro to the subjunctive", "reading": "<p><span class=\"tier-h\">H</span> The <strong>perfect tense</strong> (have/has done) = present of <em>haber</em> + past participle: <span data-say=\"he estudiado\">he estudiado</span> (I have studied), <span data-say=\"ha comido\">ha comido</span> (he/she has eaten).</p>\n            <p>The <strong>pluperfect</strong> (had done) = imperfect of <em>haber</em> + past participle: <span data-say=\"había terminado\">había terminado</span> (I had finished) — used for something that had ALREADY happened before another past event.</p>\n            <p><span class=\"tier-h\">H</span> After certain trigger phrases like <span data-say=\"es importante que\">es importante que</span> (it’s important that) or a future-time <span data-say=\"cuando\">cuando</span> (when), Spanish switches to the <strong>present subjunctive</strong>: <span data-say=\"Es importante que estudies mucho.\">Es importante que estudies mucho.</span> (It’s important that you study a lot.) / <span data-say=\"Cuando llegue a casa, cenaré.\">Cuando llegue a casa, cenaré.</span> (When I get home, I will have dinner.)</p>", "question": "Which sentence correctly uses the present subjunctive after a trigger phrase?", "options": ["Es importante que estudies mucho", "Es importante que estudias mucho", "Es importante estudiar que mucho", "Estudiarás mucho, es importante"]}'::jsonb, '{"answer": 0, "explain": "‘es importante que’ + a change of subject triggers the subjunctive (estudies), not the ordinary present indicative (estudias)."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:misc:cd2a258c', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Voy estudiar esta noche.</p><p><strong>✅ The correct idea:</strong> Voy a estudiar esta noche.</p>", "question": "What is missing from ‘Voy estudiar esta noche’?", "options": ["the linking word ‘a’ (voy a estudiar)", "an accent on the final letter of ‘voy’", "the subject pronoun ‘yo’ at the start", "the word ‘esta’ before ‘noche’"]}'::jsonb, '{"answer": 0, "explain": "ir a + infinitive always needs ‘a’ between the conjugated ir and the infinitive."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:misc:4fa0134b', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Yo tenerá mucho dinero.</p><p><strong>✅ The correct idea:</strong> Yo tendré mucho dinero.</p>", "question": "Why is ‘tenerá’ wrong for the future of tener?", "options": ["tener has the irregular future stem tendr-, not tener-", "the ending should be -ería instead of the future ending -á", "‘tenerá’ is actually a correctly formed present-tense verb", "‘tenerá’ only needs an accent added on the very first e"]}'::jsonb, '{"answer": 0, "explain": "tener changes to the irregular stem tendr- before ANY future ending: tendré, tendrás, tendrá…"}'::jsonb),
